import{_ as o,o as t,c as n,i as a}from"./chunks/framework.DP1yFSuu.js";const u=JSON.parse('{"title":"Contributing & Roadmap FAQ","description":"Common questions about contributions, component proposals, design feedback, release notes, and component readiness.","frontmatter":{"title":"Contributing & Roadmap FAQ","description":"Common questions about contributions, component proposals, design feedback, release notes, and component readiness."},"headers":[],"relativePath":"faqs/contributing-and-roadmap.md","filePath":"faqs/contributing-and-roadmap.md"}'),i={name:"faqs/contributing-and-roadmap.md"};function s(r,e,l,c,d,h){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="contributing-roadmap-faq" tabindex="-1">Contributing &amp; Roadmap FAQ <a class="header-anchor" href="#contributing-roadmap-faq" aria-label="Permalink to &quot;Contributing &amp; Roadmap FAQ&quot;">​</a></h1><p>These questions cover how teams participate in Cobalt’s evolution and where to look for maturity and planning signals.</p><h2 id="can-product-teams-contribute-directly" tabindex="-1">Can product teams contribute directly? <a class="header-anchor" href="#can-product-teams-contribute-directly" aria-label="Permalink to &quot;Can product teams contribute directly?&quot;">​</a></h2><p>Yes. The docs explicitly position Cobalt as a collaborative system, not a closed handoff queue.</p><p>Teams can contribute:</p><ul><li>bug fixes</li><li>documentation updates</li><li>design feedback</li><li>new component proposals</li><li>implementation work, once a change is aligned</li></ul><p>Start with <a href="/cobalt-design-system/contributing/how-to-contribute.html">How to Contribute</a>.</p><h2 id="how-do-i-propose-a-new-component-or-major-enhancement" tabindex="-1">How do I propose a new component or major enhancement? <a class="header-anchor" href="#how-do-i-propose-a-new-component-or-major-enhancement" aria-label="Permalink to &quot;How do I propose a new component or major enhancement?&quot;">​</a></h2><p>Use the <a href="/cobalt-design-system/contributing/component-proposal.html">Component Proposal Process</a>.</p><p>The current expectation is:</p><ul><li>verify the need is recurring</li><li>check whether an existing component can be extended</li><li>start the proposal in GitHub Discussions</li><li>document the problem, API shape, alternatives, and accessibility plan</li></ul><h2 id="how-do-i-contribute-design-feedback" tabindex="-1">How do I contribute design feedback? <a class="header-anchor" href="#how-do-i-contribute-design-feedback" aria-label="Permalink to &quot;How do I contribute design feedback?&quot;">​</a></h2><p>Design feedback usually starts in one of two places:</p><ul><li>GitHub Discussions for early design-system conversation</li><li>design proposal or contribution threads when the change is more concrete</li></ul><p>If the feedback affects Figma library content, token usage, or handoff expectations, the related starting points are:</p><ul><li><a href="/cobalt-design-system/contributing/design-contribution.html">Design Contributions</a></li><li><a href="/cobalt-design-system/contributing/figma-handoff.html">Figma Handoff</a></li></ul><h2 id="where-do-i-find-release-notes-and-roadmap-context" tabindex="-1">Where do I find release notes and roadmap context? <a class="header-anchor" href="#where-do-i-find-release-notes-and-roadmap-context" aria-label="Permalink to &quot;Where do I find release notes and roadmap context?&quot;">​</a></h2><p>Use these pages first:</p><ul><li><a href="/cobalt-design-system/release-notes.html">Release Notes</a></li><li><a href="/cobalt-design-system/components/status.html">Component Status</a></li></ul><p>The docs do not currently provide a full in-site roadmap page. For broader planning context, use the release notes, current component status, and the relevant GitHub Discussions or backlog references mentioned in the product-management and contribution docs.</p><h2 id="how-do-i-know-whether-a-component-is-production-ready" tabindex="-1">How do I know whether a component is production-ready? <a class="header-anchor" href="#how-do-i-know-whether-a-component-is-production-ready" aria-label="Permalink to &quot;How do I know whether a component is production-ready?&quot;">​</a></h2><p>Look at the component’s documentation as a package of signals:</p><ul><li><a href="/cobalt-design-system/components/status.html">Component Status</a></li><li>the component page’s accessibility report</li><li>examples and usage guidance</li><li>changelog history</li></ul><p>If a component is still evolving, those pages should give you a better signal than a single “yes/no” label alone.</p><h2 id="what-do-i-do-if-the-token-or-component-i-need-does-not-exist" tabindex="-1">What do I do if the token or component I need does not exist? <a class="header-anchor" href="#what-do-i-do-if-the-token-or-component-i-need-does-not-exist" aria-label="Permalink to &quot;What do I do if the token or component I need does not exist?&quot;">​</a></h2><p>First determine which kind of gap you found:</p><ul><li>if it is a <strong>token gap</strong>, use the token decision guidance in <a href="/cobalt-design-system/tokens/structure.html">Token Structure</a></li><li>if it is a <strong>component gap</strong>, use the <a href="/cobalt-design-system/contributing/component-proposal.html">Component Proposal Process</a></li><li>if you are not sure which it is, start with <a href="https://github.com/vizualization-lab/cobalt-design-system/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a></li></ul><p>The goal is to avoid inventing one-off values or components when the need is really a shared system change.</p><h2 id="do-i-need-a-changeset-for-docs-only-or-user-facing-changes" tabindex="-1">Do I need a changeset for docs-only or user-facing changes? <a class="header-anchor" href="#do-i-need-a-changeset-for-docs-only-or-user-facing-changes" aria-label="Permalink to &quot;Do I need a changeset for docs-only or user-facing changes?&quot;">​</a></h2><p>If the change is user-facing and follows the repo’s release process, expect to add a changeset unless the maintainers explicitly scope it out.</p><p>When in doubt, check:</p><ul><li><a href="/cobalt-design-system/contributing/how-to-contribute.html">How to Contribute</a></li><li><a href="/cobalt-design-system/contributing/versioning.html">Versioning &amp; Releases</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/cobalt-design-system/contributing/how-to-contribute.html">How to Contribute</a></li><li><a href="/cobalt-design-system/contributing/component-proposal.html">Component Proposal Process</a></li><li><a href="/cobalt-design-system/contributing/versioning.html">Versioning &amp; Releases</a></li><li><a href="/cobalt-design-system/components/status.html">Component Status</a></li></ul>',34)])])}const m=o(i,[["render",s]]);export{u as __pageData,m as default};
